    <nav class="settings-nav">
        <button class="nav-item @(activeSection == "profile" ? "active" : "")" 
                @onclick="() => SelectSection("profile")">
            <span class="icon">👤</span>
            <span>Profile</span>
        </button>
        <button class="nav-item @(activeSection == "notifications" ? "active" : "")" 
                @onclick="() => SelectSection("notifications")">
            <span class="icon">🔔</span>
            <span>Notifications</span>
        </button>
        <button class="nav-item @(activeSection == "security" ? "active" : "")" 
                @onclick="() => SelectSection("security")">
            <span class="icon">🔒</span>
            <span>Security</span>
        </button>
        <button class="nav-item @(activeSection == "appearance" ? "active" : "")" 
                @onclick="() => SelectSection("appearance")">
            <span class="icon">🎨</span>
            <span>Appearance</span>
        </button>
    </nav>
</div>

@code {
    [Parameter]
    public string ActiveSection { get; set; } = "profile";

    [Parameter]
    public EventCallback<string> OnSectionChanged { get; set; }

    private string activeSection;

    protected override void OnInitialized()
    {
        activeSection = ActiveSection;
    }

    private async Task SelectSection(string section)
    {
        activeSection = section;
        await OnSectionChanged.InvokeAsync(section);
    }
}
