            {
                <div class="alert alert-danger py-2" role="alert">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="alert alert-success py-2" role="alert">✅ Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
