@if (Visible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Device</strong> in <strong>@Location</strong>?</p>
                    <p class="text-muted small">This will immediately sign out that device.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_265be80becbf417bb05a68211a3d0836.Services

<div class="section-panel">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <hr />

    <div class="d-flex align-items-center justify-content-between mb-4">
        <div>
            <h6 class="mb-1">Two-Factor Authentication</h6>
            <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="twoFactor"
                   checked="@Security.TwoFactorEnabled" disabled />
        </div>
    </div>

    @if (Security.LastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <hr />

    <h6 class="mb-3">Active Sessions</h6>
    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead class="table-light">
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Security.Sessions)
                {
                    var isCurrent = session == Security.Sessions.FirstOrDefault();
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-primary ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => ShowRevokeDialog(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

<SessionRevokeDialog Visible="_showRevokeDialog"
                     Device="@(_sessionToRevoke?.Device ?? "")"
                     Location="@(_sessionToRevoke?.Location ?? "")"
                     OnConfirm="ConfirmRevokeAsync"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

