@using sv_265be80becbf417bb05a68211a3d0836.Services

<div class="section-panel">
    <h4 class="mb-4">Appearance Settings</h4>

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6 class="mb-2">Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")"
                               value="@theme"
                               checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6 class="mb-2">Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")"
                               value="@size"
                               checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <label class="form-label fw-semibold">Language</label>
                <select class="form-select" @bind="Language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (_showSuccess)
            {
                <div class="alert alert-success mt-3 py-2" role="alert">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>

        <div class="col-md-6">
            <h6 class="mb-2">Live Preview</h6>
            <div class="preview-container p-3 rounded border @PreviewThemeClass"
                 style="@PreviewFontStyle">
                <div class="@(CompactMode ? "mb-1" : "mb-3")">
                    <strong>Dashboard</strong>
                </div>
                <div class="@(CompactMode ? "mb-1" : "mb-2")">
                    <span class="badge @PreviewBadgeClass">3 new</span>
                    Welcome back! You have new notifications.
                </div>
                <div class="preview-card p-2 rounded @(CompactMode ? "mb-1" : "mb-2")"
                     style="@PreviewCardBg">
                    <div class="@(CompactMode ? "" : "fw-semibold")">Sample Card</div>
                    <small class="@PreviewMutedClass">This is how content will look with your settings.</small>
                </div>
                <div>
                    <button class="btn btn-sm @PreviewButtonClass" disabled>Sample Button</button>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "en";
    private bool CompactMode;

    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private string PreviewThemeClass => Theme switch
    {
        "Dark" => "bg-dark text-light",
        _ => "bg-light text-dark"
    };

    private string PreviewBadgeClass => Theme == "Dark" ? "bg-info" : "bg-primary";

    private string PreviewButtonClass => Theme == "Dark" ? "btn-outline-light" : "btn-outline-primary";

    private string PreviewMutedClass => Theme == "Dark" ? "text-light opacity-75" : "text-muted";

    private string PreviewCardBg => Theme == "Dark"
        ? "background-color: #374151;"
        : "background-color: #f8f9fa;";

    private string PreviewFontStyle => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;

        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.section-panel {
    padding: 1.5rem;
}

.preview-container {
    min-height: 200px;
    transition: all 0.2s ease;
}

